import React, { useCallback, useEffect, useState, useRef } from 'react'
import { ShadowScroller } from '@fs/zion-ui/quarks-authorized-use-only'
import { css } from '@linaria/core'
import { Trans, useTranslation } from 'react-i18next'
import { Link, useHistory } from '@fs/zion-router'
import {
  ContentAdd,
  HelpAskQuestion,
  LogoFamilysearch,
  LogoRootstech,
  PersonGroup,
  ThingPresentation,
} from '@fs/zion-icon'
import {
  Button,
  Paragraph,
  ListItem,
  MarginBox,
  useStatusOverlay,
  Row,
  Separator,
  colors,
  BillboardText,
} from '@fs/zion-ui'
import { i18n } from '@fs/zion-locale'
import { format } from '@fs/zion-locale/date-fns'
import { chatAvatar } from '../chat-avatar/chatAvatar'
import { useChatState } from '../providers/ChatStateProvider'
import ChatInviteProfileSearch from '../chat-profile-search/ChatInviteProfileSearch'
import { getChannelMembers, getChannelName } from '../helpers/stream/streamChatHelper'
import {
  isRootsTechChannel,
  isPublicChannel,
  isSessionChannel,
  isVendorChannel,
  isSupportChannel,
  isDirectChannel,
  isManagedChannel,
  isHelperConnectChannel,
} from '../services/fsChat/fsChatService'
import ChatParticipantsPaginatedContents from './ChatParticipantsPaginatedContents'
import GroupDetailsMonogram from './ChatDetailsMonogram'
import { channelMemberToParticipantChip } from '../chat-create/ChatCreateTo'
import { FS_DIRECT_MAX_PARTICIPANT_COUNT } from '../services/fsChat/fsChannelEnums'
import { addOrRemoveChannelMembers, useCurrentChannel } from '../hooks/channelHooks'
import useChatLog from '../hooks/useChatLog'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'
import { LOG_LEVEL } from '../global/chatLog'

const chatCreateCss = css`
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  flex-grow: 1;
  flex-shrink: 1;
  overflow: auto;
`

function getGroupDetailStartElement({ channel, isPrivateGroup }) {
  let startElement
  if (isSessionChannel(channel)) {
    startElement = <ListItem.Icon Icon={ThingPresentation} />
  } else if (isRootsTechChannel(channel)) {
    startElement = <ListItem.Icon Icon={LogoRootstech} />
  } else if (isVendorChannel(channel)) {
    startElement = <ListItem.Avatar src={channel?.data?.image} />
  } else if (isSupportChannel(channel)) {
    startElement = <ListItem.Icon Icon={HelpAskQuestion} />
  } else if (isPrivateGroup) {
    startElement = chatAvatar({ name: channel?.name || '', isGroup: true })
  } else if (isHelperConnectChannel(channel)) {
    startElement = <ListItem.Icon Icon={LogoFamilysearch} background={colors.green30} color={colors.gray00} />
  } else {
    startElement = <ListItem.Icon Icon={PersonGroup} />
  }
  return startElement
}

function getGroupDetailsSecondaryText({ channel, participants, isPrivateGroup }) {
  let secondaryText = null
  if (isPrivateGroup && Array.isArray(participants)) {
    secondaryText = i18n.t(
      'chat.participants-count.label',
      '{count, plural, =0 {No participants} one {# Participant} other {# Participants}}',
      { count: participants.length }
    )
  } else if (!isVendorChannel(channel)) {
    secondaryText = channel?.data?.description
  }
  return secondaryText
}

export default function ChatDetails() {
  const [t] = useTranslation()
  const { log, track } = useChatLog({ component: '[ChatDetails]' })
  const history = useHistory()
  const { client, createChatRecipientChipCollection } = useChatState()
  const clientUserId = client?.userID
  const { resetChips, addChip } = createChatRecipientChipCollection
  const channel = useCurrentChannel()

  const [participants, setParticipants] = useState([])
  const isNewGroup = history?.location?.state?.isNewGroup
  const isPrivateGroup = isDirectChannel(channel)
  const showStatusOverlay = useStatusOverlay()
  const isPublicGroup = isPublicChannel(channel)
  const isManagedGroup = isManagedChannel(channel)
  const isHelperConnect = isHelperConnectChannel(channel)

  const onClickPrivateGroupInvitePeople = useCallback(async () => {
    resetChips()
    participants.forEach((participant) => {
      const userId = participant?.user?.id
      if (userId !== clientUserId) {
        addChip(channelMemberToParticipantChip({ member: participant, t }))
      }
    })
    const cisIds = participants.map((p) => p?.user?.fs_cis_id)
    track({ link_name: 'Chat:Create Multi-user Chat:Click Add Users ' }, { chatTargetUserIds: cisIds })
    history.push(buildChatRoute(CHAT_ROUTE_KEY.CREATE_EMPTY_DIRECT_CHAT))
  }, [addChip, clientUserId, resetChips, participants, history, t, track])

  const handleGoToChatClick = () => history.push(buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid: channel?.cid }))

  // keep full list of members in memory
  useEffect(() => {
    setParticipants(getChannelMembers({ channel }))
  }, [channel])

  const focusRef = useRef()
  useEffect(() => {
    const current = focusRef?.current
    setTimeout(() => current?.focus(), 0)
    return () => {
      current?.blur()
    }
  }, [channel.cid])

  const onClickSuggestion = async (s) => {
    const cisId = s.key
    try {
      track(
        { link_name: `Chat:Add User To Chat:${channel?.type}` },
        { chatTargetUserIds: [cisId], chatChannelId: channel?.cid }
      )
      await addOrRemoveChannelMembers({ cid: channel?.cid, cisIdsToAdd: [cisId], log })
      setParticipants(getChannelMembers({ channel }))

      if (isVendorChannel(channel) || isSupportChannel(channel)) {
        showStatusOverlay({
          type: 'success',
          message: t('chat.group.add.sent', 'Adding {name} to the chat.', {
            name: s.displayName || s.primaryText,
          }),
          dismissable: true,
        })
      } else {
        showStatusOverlay({
          type: 'success',
          message: t('chat.public-group-invite-sent.message', 'An invite has been sent to {name}.', {
            name: s.displayName || s.primaryText,
          }),
          dismissable: true,
        })
      }
    } catch (error) {
      if (error.response?.status === 400) {
        showStatusOverlay({
          message: t('chat.create-button-disabled.label', 'Unable to Message This User'),
          type: 'warning',
          dismissable: true,
          transient: true,
          actionLabel: t('common-ui:learn-more.action', 'Learn More'),
          actionCallback: () => {
            window.open(
              'https://www.familysearch.org/en/help/helpcenter/article/familysearch-chat-frequently-asked-questions-faqs',
              '_blank'
            )
          },
        })
      } else {
        log({ msg: `failed to add user to chat: ${error}`, level: LOG_LEVEL.ERROR })
        showStatusOverlay({
          type: 'error',
          message: t('chat.group.add.failed', 'Adding {name} to the chat failed.', {
            name: s.displayName || s.primaryText,
          }),
          dismissable: true,
          transient: true,
        })
      }
    }
  }

  const timeStamp = channel?.data?.created_at
    ? format(new Date(channel.data.created_at), 'PPPP, p', { locale: i18n.Language })
    : undefined
  const createDate = t('chat.public-group.date', `Created {date}`, { date: timeStamp })
  const startElement = getGroupDetailStartElement({ channel, isPrivateGroup })
  const secondaryText = getGroupDetailsSecondaryText({ channel, isPrivateGroup, participants })
  const primaryText = getChannelName({ channel, excludeUserId: clientUserId })

  return (
    <div data-testid="chat-group-details" className={chatCreateCss}>
      <ShadowScroller>
        <div style={{ padding: '12px 22px' }}>
          <ListItem
            primaryText={primaryText}
            secondaryText={secondaryText}
            startElement={startElement}
            ref={focusRef}
            tabIndex={-1}
          />
          {!isSessionChannel(channel) && !isManagedGroup && <GroupDetailsMonogram channel={channel} />}
          <Separator size="xxs" />
          {isPublicGroup && (
            <>
              {timeStamp && (
                <BillboardText primaryColor={colors.gray70}>
                  <Paragraph size="xs">{createDate}</Paragraph>
                </BillboardText>
              )}
              <Trans
                i18nKey="chat.public-group.label"
                defaults="Public Chats are for topics of general interest. For research questions, try our <0>Help Page</0>. Any RootsTech attendee can join this Public Chat."
                components={[<Link to="https://www.familysearch.org/rootstech/?help" target="_blank" external />]}
              />
            </>
          )}
          <Separator size="nano" />
          {!isPrivateGroup && participants && !isManagedGroup && !isHelperConnect && (
            <ChatInviteProfileSearch
              label={t('chat.invite-people.action', 'Invite People')}
              excludedUsers={participants.map((p) => ({ cisId: p?.user?.fs_cis_id }))}
              onClickSuggestion={onClickSuggestion}
              openAutosuggestByDefault={isNewGroup}
            />
          )}
          {isPrivateGroup && (
            <>
              <Row style={{ paddingTop: 12 }}>
                <Button data-testid="chat-invite-people" Icon={ContentAdd} onClick={onClickPrivateGroupInvitePeople}>
                  {t('chat.invite-people.action', 'Invite People')}
                </Button>
              </Row>
              <Paragraph size="xs">
                {t(
                  'chat.invite-others-instructions.message',
                  'Invite others to a new private chat (up to {maxParticipants} total).',
                  { maxParticipants: FS_DIRECT_MAX_PARTICIPANT_COUNT }
                )}
              </Paragraph>
            </>
          )}

          <ChatParticipantsPaginatedContents participants={participants} />
        </div>
      </ShadowScroller>
      <MarginBox marginX="xs" marginY="xs">
        <Row alignX="end">
          <Button data-testid="start-group-chat" emphasis="high" onClick={handleGoToChatClick}>
            {isNewGroup
              ? t('chat.start-group-chat.action', 'Start Public Chat')
              : t('chat.go-to-group-by-invite-link.button', 'Go to Chat')}
          </Button>
        </Row>
      </MarginBox>
    </div>
  )
}
