import React, { useMemo, useState } from 'react'
import ChatLoadMoreButton from '../chat-buttons/ChatLoadMoreButton'
import NoResultsText from '../chat/NoResultsText'
import ChatParticipants from './ChatParticipants'

export default function ChatParticipantsPaginatedContents({ participants, pageSize = 10 }) {
  const [visibleCount, setVisibleCount] = useState(pageSize)
  const paginatedResults = useMemo(() => (participants || []).slice(0, visibleCount), [participants, visibleCount])

  const handleShowMore = () => setVisibleCount(visibleCount + pageSize)
  const hasMoreItemsToShow = visibleCount < participants?.length
  const hasResults = paginatedResults?.length > 0 || false

  return (
    <>
      {hasResults ? <ChatParticipants people={paginatedResults} /> : <NoResultsText />}
      {hasMoreItemsToShow && <ChatLoadMoreButton handleClick={handleShowMore} />}
    </>
  )
}
