import React from 'react'
import { useTranslation } from 'react-i18next'
import { List, ListSubSection } from '@fs/zion-ui'
import ChatPersonObject from './ChatPersonObject'

export default function ChatParticipants({ people }) {
  const [t] = useTranslation()

  return (
    people?.length > 0 && (
      <ListSubSection heading={t('chat.group-members.heading', 'Chat Members')}>
        <List>
          {people.map((person) => (
            <ChatPersonObject key={person?.user_id} person={person} />
          ))}
        </List>
      </ListSubSection>
    )
  )
}
