import React from 'react'
import { useTranslation } from 'react-i18next'
import { Ellipsis, PersonBlock } from '@fs/zion-ui'
import { getSessionId } from '@fs/zion-session'
import { getPortraitUrlFromCisId } from '../helpers/portraitServiceHelper'

export default function GroupDetailsMonogram({ channel }) {
  const [t] = useTranslation()
  const cisId = channel?.data?.fs_created_by_cis_id || ''
  const memberId = channel?.data?.fs_created_by_stream_id || ''
  const name = channel?.state?.members[memberId]?.user?.name || ''
  const creatorName = name || channel?.data?.created_by?.name
  const isOnline = channel?.data?.created_by?.online
  const portraitUrl =
    `${channel?.state?.members[memberId]?.user?.fs_image_icon}?sessionId=${getSessionId()}` ||
    getPortraitUrlFromCisId(cisId)
  const monogram = name.charAt(0)

  return (
    <PersonBlock
      size="md"
      avatarProps={{ src: portraitUrl || '', monogram, presence: isOnline ? 'online' : null }}
      name={<Ellipsis>{creatorName}</Ellipsis>}
      details={t('chat.creator.label', 'Creator')}
      nameProps={{ as: 'h2' }}
    />
  )
}
