import React from 'react'
import { Button, Row } from '@fs/zion-ui'
import { NoticeLoading } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'

export default function ChatLoadMoreButton({ handleClick, label, isPending, showSpinner }) {
  const [t] = useTranslation()
  const labelText = label || t('chat.show-more.label', 'View More')

  return (
    <Row alignX="center">
      <Button
        data-testid="show-more"
        onClick={handleClick}
        emphasis="low"
        Icon={isPending && showSpinner ? NoticeLoading : undefined}
        disabled={isPending}
      >
        {labelText}
      </Button>
    </Row>
  )
}
